const raw = items[0].json.candidates[0].content.parts[0].text;

const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No JSON found in response: ' + raw);
}

const parsed = JSON.parse(jsonMatch[0]);
return [{ json: parsed }];

const judgeRaw = $('Judge Agent').item.json.candidates[0].content.parts[0].text;
const criticRaw = $('Critic Agent').item.json.candidates[0].content.parts[0].text;

const unescape = (str) => str
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

const judgeText = unescape(judgeRaw);
let criticText = unescape(criticRaw);

const bodyMatch = criticText.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
if (bodyMatch) {
  criticText = bodyMatch[1];
} else {
  criticText = criticText
    .replace(/<!DOCTYPE[^>]*>/gi, '')
    .replace(/<html[^>]*>/gi, '')
    .replace(/<\/html>/gi, '')
    .replace(/<head[^>]*>[\s\S]*?<\/head>/gi, '')
    .replace(/<body[^>]*>/gi, '')
    .replace(/<\/body>/gi, '')
    .trim();
}

const travelerEmail = $('Parse Gemini Response').item.json.traveler_email;
const destination = $('Parse Gemini Response').item.json.destination_city;

return [{
  json: {
    html_body: judgeText + criticText,
    traveler_email: travelerEmail,
    destination: destination
  }
}];

